  @field w ds  @ 10
  @field r fx  @ 30,41,46,56,60,70,76
  @field r id  @ 41,56,70
  @field w ident  @ 28,40,55,69
  @field r ins  @ 31,47,61,77
  @field w ins  @ 39,43,58,68,72,74
  @field w name  @ 25,36,52,65
  @field r outs  @ 32,48,78
  @field w outs  @ 39,44,68,73
  @field r pinMaps  @ 30,46,60,76
  @field w pinMaps  @ 43,58,72,74
